B.Xv=new A.el("spoilage-signs","\ud83d\udc43","Is it still good?","Sight, smell and texture checks for produce, dairy, meat and eggs.",B.a5H)
B.X7=new A.fy('Bacteria grow quickly at room temperature, especially on cooked and perishable foods. These limits exist to keep you out of the "danger zone" between 40\xb0F (4\xb0C) and 140\xb0F (60\xb0C).')
B.WW=new A.cs("Safe time limits")
B.a_w=s(["2 hours maximum at normal room temperature.","1 hour if the room is above 90\xb0F (32\xb0C).","Refrigerate leftovers promptly in shallow containers."],t.s)
B.W7=new A.cE(B.a_w)
B.Wq=new A.eX("\u274c","Never leave cooked dishes out overnight \u2014 the reheat the next day will not undo the bacterial growth.")
