B.Xz=new A.el("leaving-out","\u23f1\ufe0f","How long food can sit out","Room-temperature safety windows for cooked and perishable food.",B.a5K)
B.WH=new A.cs("Refrigerator best practices")
B.a3c=s(["Keep the fridge at or below 40\xb0F (4\xb0C).","Store raw meat on the bottom shelf so drips can't reach other food.","Use airtight containers for leftovers.","Label leftovers with the preparation date."],t.s)
B.W6=new A.cE(B.a3c)
B.Wx=new A.cs("Pantry tips")
B.a3h=s(["Store dry and canned goods in a cool, dry spot.","Keep opened dry goods in sealed containers \u2014 moisture is the enemy.","Use First In, First Out: place new stock behind older stock."],t.s)
B.VL=new A.cE(B.a3h)
B.a29=s([B.WH,B.W6,B.Wx,B.VL],t.F)
B.Xk=new A.el("fridge-pantry","\ud83e\uddca","Fridge & pantry storage","Temperatures, shelf order, and keeping dry goods dry.",B.a29)
B.Xe=new A.fy("Freezing slows spoilage dramatically and can rescue food you know you won't finish in time. The only real limit is quality degradation \u2014 freezer burn and texture loss.")
B.WM=new A.cs("Best practices")
B.a_U=s(["Freeze food before it spoils, not after.","Use freezer-safe airtight packaging.","Remove as much air as possible (press flat, vacuum seal if you have one).","Label every package with the freeze date."],t.s)
B.VX=new A.cE(B.a_U)
B.Wy=new A.cs("Typical freezer storage times")
B.a65=s(["Meat: 6\u201312 months.","Cooked meals: 2\u20133 months.","Fruits and vegetables: 8\u201312 months.","Bread: 2\u20133 months."],t.s)
B.VS=new A.cE(B.a65)
B.Wu=new A.eX("\u2705","Frozen food stays technically safe indefinitely \u2014 but quality degrades, so rotate the freezer too.")
B.a5v=s([B.Xe,B.WM,B.VX,B.Wy,B.VS,B.Wu],t.F)
B.Xj=new A.el("freezing","\u2744\ufe0f","Freezing food safely","What to freeze, how to package, how long it keeps.",B.a5v)
B.WE=new A.cs("The numbers")
B.a_l=s(["About one third of all food produced globally is wasted.","Food waste is a major contributor to greenhouse-gas emissions.","Households are among the largest single sources of food waste."],t.s)
B.VV=new A.cE(B.a_l)
B.uB=new A.cs("SDG 12.3")
B.X9=new A.fy("UN Sustainable Development Goal 12.3 aims to halve global food waste per capita by 2030 \u2014 a target that the household tier needs to hit to succeed.")
B.WX=new A.cs("What you can do")
B.XI=s(["Learn how to read food labels so you don't discard good food.","Store food properly (see the fridge & pantry topic).","Freeze food before it spoils.","Use leftovers creatively \u2014 soups, stir-fries, frittatas.","Buy only what you need and shop more frequently if you can."],t.s)
B.VZ=new A.cE(B.XI)
B.Wo=new A.eX("\ud83c\udf0d","Small household changes compound into meaningful system-level impact.")
B.Zt=s([B.WE,B.VV,B.uB,B.X9,B.WX,B.VZ,B.Wo],t.F)
B.Xw=new A.el("reducing-waste","\u267b\ufe0f","Reducing food waste & SDG 12.3","Why it matters, and what UN Goal 12.3 asks of households.",B.Zt)
B.Xd=new A.fy("These are the default conventions you'll see in US grocery stores and home kitchens. Knowing them helps you read labels and store things correctly.")
B.uA=new A.cs("Storage defaults")
B.a2P=s(["Eggs: washed at the supplier \u2014 must be refrigerated.","Milk: pasteurized, refrigerated, 7\u201314 days after opening.","Bread: often refrigerated, plastic-wrapped.","Hard cheese: any mold treated as spoilage.","Potatoes and tomatoes: often refrigerated by default.","Shopping cadence: large, infrequent trips."],t.s)
B.VQ=new A.cE(B.a2P)
B.uC=new A.cs("Date labels")
B.a61=s(['"Best By" = quality, not safety. Almost always still safe past it.','"Use By" usually means quality too \u2014 the only true exception is infant formula.',"Dates drive a lot of household discards. Trust your senses first."],t.s)
B.VT=new A.cE(B.a61)
B.ux=new A.cs("Cultural defaults")
B.a67=s(['"When in doubt, throw it out" is the common reflex.',"Low tolerance for any mold.","The fridge tends to be the default answer for storage.","Plastic, airtight packaging is the norm."],t.s)
B.W2=new A.cE(B.a67)
B.Wn=new A.eX("\u2705","Pause before tossing on the printed date \u2014 for most items it's a quality marker, not a safety one.")
B.a2D=s([B.Xd,B.uA,B.VQ,B.uC,B.VT,B.ux,B.W2,B.Wn],t.F)
B.Xx=new A.el("local-habits-us","\ud83c\uddfa\ud83c\uddf8","Food habits in the US","How storage, labels, and shopping work in the US.",B.a2D)
B.X8=new A.fy("These are the default conventions you'll see in Swiss grocery stores and home kitchens. They lean toward smaller, more frequent shops and selective refrigeration.")
B.a0O=s(["Eggs: unwashed; keep at room temperature for up to ~21 days.","UHT milk is common \u2014 shelf-stable until opened.","Bread: never refrigerated; store in paper or cloth.","Hard cheese: trim small mold off, keep breathable.","Potatoes: cool, dark, ventilated. Tomatoes: room temperature.","Shopping cadence: smaller, more frequent trips."],t.s)
B.W3=new A.cE(B.a0O)
B.a6m=s(['"Mindestens haltbar bis" / "\xc0 consommer de pr\xe9f\xe9rence avant" = quality indicator. Likely fine after the date.','"Zu verbrauchen bis" / "\xc0 consommer jusqu\'au" is a strict safety date \u2014 illegal for shops to sell past it.',"Sensory checks are encouraged \u2014 look, smell, taste-of-doubt."],t.s)
B.Wa=new A.cE(B.a6m)
B.a19=s(['"Assess the condition before discarding" is the common reflex.',"Mold tolerance depends on the product (cured meats, hard cheese).","Selective refrigeration \u2014 not everything goes in the fridge.","Paper, breathable, minimal packaging is the norm."],t.s)
